[125] يُنظر: ((تفسير ابن جرير)) (24/20)، ((تفسير القرطبي)) (19/176)، ((تفسير ابن كثير)) (8/305)، ((تفسير السعدي)) (ص: 907)، ((تفسير ابن عاشور)) (30/33)، ((تفسير ابن عثيمين- جزء عم)) (ص: 30). قال الماوَرْدي: (وَسُيِّرَتِ الْجِبَالُ فَكَانَتْ سَرَابًا فيه وجهانِ: أحدُهما: سُيِّرَتْ أي: أُزيلَتْ عن مَواضِعِها. الثَّاني: نُسِفَتْ مِن أُصولِها). ((تفسير الماوردي)) (6/185). قال ابنُ عاشور: (السَّرابُ: ما يَلُوحُ في الصَّحاري مِمَّا يُشبِهُ الماءَ وليس بماءٍ، ولكِنَّه حالةٌ في الجوِّ القَريبِ تَنشَأُ مِن تَراكُمِ أبْخِرَةٍ على سَطحِ الأرضِ). ((تفسير ابن عاشور)) (30/33). وقال ابن عطيَّة: (وقولُه تعالى: فَكَانَتْ سَرَابًا عِبارةٌ عن تلاشيها وفَنائِها بعْدَ كَونِها هَباءً مُنْبَثًّا، ولم يَرِدْ أنَّ الجبالَ تعودُ تُشبِهُ الماءَ على بُعدٍ مِن النَّاظِرِ إليها). ((تفسير ابن عطية)) (5/425). وقال الشنقيطي: (ذكَرَ جلَّ وعلا أنَّه يَجعلُ الجبالَ سَرابًا، فقال: وَسُيِّرَتِ الْجِبَالُ فَكَانَتْ سَرَابًا. وبيَّن في موضعٍ آخَرَ أنَّ السَّرابَ عِبارةٌ عن لا شَيءَ؛ وهو قولُه: وَالَّذِينَ كَفَرُوا أَعْمَالُهُمْ كَسَرَابٍ بِقِيعَةٍ إلى قولِه: لَمْ يَجِدْهُ شَيْئًا
[النور: 39]
). ((أضواء البيان)) (3/283) بتصرف. وقال البِقاعي: (وَسُيِّرَتِ أي: حُمِلَت بأيسَرِ أمرٍ على السَّيرِ الْجِبَالُ على ما تَعلَمونَ مِن صَلابتِها وصُعوبتِها في الهواءِ، كأنَّها الهباءُ المنثورُ، وعلى ذلك دَلَّ قَولُه: فَكَانَتْ أي: كَيْنونةً راسخةً سَرَابًا أي: لا نرى فيها إلَّا خَيالًا يتراءى، وهي سائِرةٌ تَمُرُّ مَرَّ السَّحابِ، ثمَّ تخفى؛ لتناثُرِ أجزائِها كالهَباءِ). ((نظم الدرر)) (21/202). قال الألوسي: (فَكَانَتْ سَرَابًا أي: فصارتْ بعدَ تسييرِها مِثلَ سرابٍ، فتُرى بعدَ تفَتُّتِها وارتفاعِها في الهواءِ كأنَّها جبالٌ، وليست بجبالٍ، بل غُبارٌ غليظٌ مُتراكِمٌ يُرى مِن بعيدٍ كأنَّه جبلٌ، كالسَّرابِ يُرى كأنَّه بحرٌ مثلًا، وليس به). ((تفسير الألوسي)) (15/213).

[280] يُنظر: ((تفسير ابن جرير)) (24/45)، ((تفسير القرطبي)) (19/186)، ((مجموع الفتاوى)) لابن تيمية (14/397)، ((تفسير ابن كثير)) (8/309)، ((تفسير ابن عاشور)) (30/50). ممَّن اختار أنَّ الضَّميرَ في قولِه: لَا يَمْلِكُونَ يعودُ على جميعِ الخَلقِ مِن أهلِ السَّمواتِ والأرضِ: ابنُ جرير، ومكِّي، والزمخشري، والرازي، والبيضاوي، والعُلَيمي، والألوسي، والسعدي. يُنظر: ((تفسير ابن جرير)) (24/45)، ((الهداية إلى بلوغ النهاية)) لمكي (12/8010)، ((تفسير الزمخشري)) (4/691)، ((تفسير الرازي)) (31/24)، ((تفسير البيضاوي)) (5/281)، ((تفسير العليمي)) (7/266)، ((تفسير الألوسي)) (15/219)، ((تفسير السعدي)) (ص: 908). وقال ابن عثيمين: (وقولُه: لَا يَمْلِكُونَ مِنْهُ خِطَابًا يعني: أنَّ النَّاسَ لا يَملِكونَ الخِطابَ مِن الله، ولا يَستطيعُ أحدٌ أن يَتكلَّمَ إلَّا بإذْنِ اللهِ). ((تفسير ابن عثيمين- جزء عم)) (ص: 36). وقال ابن عطيَّة: (وقولُه تعالى: لَا يَمْلِكُونَ الضَّميرُ للكفَّارِ، أي: لا يَملِكونَ مِن أفضالِه وأجمالِه أن يُخاطِبوه بمَعذِرةٍ ولا غيرِها، وهذا في موطنٍ خاصٍّ). ((تفسير ابن عطية)) (5/428). وقال أبو حيَّان: (والضَّميرُ في لَا يَمْلِكُونَ عائدٌ على المشرِكين، قاله عَطاءٌ عن ابنِ عبَّاسٍ، أي: لا يُخاطِبُ المشرِكون اللهَ. أمَّا المؤمنونَ فيشفَعون، ويَقبَلُ اللهُ ذلك منهم. وقيل: عائدٌ على المؤمنينَ، أي: لا يَملِكونَ أن يُخاطِبوه في أمرٍ مِن الأمورِ؛ لعِلْمِهم أنَّ ما يَفعَلُه عدلٌ منه. وقيل: عائدٌ على أهلِ السَّمواتِ والأرضِ. والضَّميرُ في مِنْهُ عائدٌ عليه تعالى). ((تفسير أبي حيان)) (10/390). وقال الشوكاني: (لَا يَمْلِكُونَ مِنْهُ خِطَابًا أي: لا يَملِكونَ أن يَسألوا إلَّا فيما أذِن لهم فيه. وقال الكِسائيُّ: لا يَملِكونَ منه خِطابًا بالشَّفاعةِ إلَّا بإذْنِه. وقيل: الخِطابُ: الكلامُ، أي: لا يَملِكونَ أن يُخاطِبوا الرَّبَّ سُبحانَه إلَّا بإذْنِه؛ دليلُه: لَا تَكَلَّمُ نَفْسٌ إِلَّا بِإِذْنِهِ
[هود: 105]
). ((تفسير الشوكاني)) (5/446). وممَّن اختار أنَّ المعنى: لا يَتكلَّمونَ مع الله، ويُمنَعون مِن الكلامِ معه: الثعلبيُّ، والسمعاني، والخازن، والسعدي، وابن عثيمين. يُنظر: ((تفسير الثعلبي)) (10/119)، ((تفسير السمعاني)) (6/142)، ((تفسير الخازن)) (4/389)، ((تفسير السعدي)) (ص: 908)، ((تفسير ابن عثيمين- جزء عم)) (ص: 36). وممَّن اختار أنَّ المعنى: لا يَملِكونَ الكلامَ بالشَّفاعةِ إلَّا بإذْنِه: السمرقنديُّ، والعُلَيمي. يُنظر: ((تفسير السمرقندي)) (3/539)، ((تفسير العليمي)) (7/266). قال البيضاوي: (لَا يَمْلِكُونَ مِنْهُ خِطَابًا ... أي: لا يَملِكونَ خِطابَه، والاعتِراضَ عليه في ثَوابٍ أو عِقابٍ؛ لأنَّهم مَمْلوكونَ له على الاطلاقِ، فلا يَستَحِقُّونَ عليه اعتِراضًا، وذلك لا يُنافي الشَّفاعةَ بإذْنِه). ((تفسير البيضاوي)) (5/281). وقال الماتُريدي: (قولُه عزَّ وجلَّ: لَا يَمْلِكُونَ مِنْهُ خِطَابًا؛ هَيْبةً مِن الله تعالى، وتعظيمًا لحقِّه؛ فلا يَملِكونَ مِن هَيْبَتِه الخِطابَ بالشَّفاعةِ أو بالخُصومةِ أو بأيِّ شيءٍ كان). ((تفسير الماتريدي)) (10/400).
